import{_ as i,o as t,c as n,ae as o}from"./chunks/framework.CyZiF_rV.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"en/tryby-offline.md","filePath":"en/tryby-offline.md"}'),a={name:"en/tryby-offline.md"};function s(l,e,r,d,f,c){return t(),n("div",null,[...e[0]||(e[0]=[o('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/tryby-offline.md" target="_blank" rel="noreferrer">tryby-offline.md</a></p></blockquote><h2 id="offline-modes" tabindex="-1">Offline modes <a class="header-anchor" href="#offline-modes" aria-label="Permalink to &quot;Offline modes&quot;">​</a></h2><p>10.07.2025</p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>The KSeF system provides two basic invoice issuing modes:</p><ul><li><code>online</code> mode - invoice issued and sent in real time to the KSeF system,</li><li><code>offline</code> mode - invoice issued and sent to KSeF at a later date, as specified by law.</li></ul><p>In offline mode, invoices are issued electronically in accordance with the applicable FA(3) structure template. The most important technical aspects:</p><ul><li>When sending an invoice – both in interactive and batch mode – the parameter <code>offlineMode: true</code> must be set.</li><li>For invoices sent as online (offlineMode: false), the KSeF system may automatically assign them offline mode - based on comparison of the issue date with the receipt date. Mechanism details: <a href="./offline/automatyczne-okreslanie-trybu-offline.html">Automatic determination of offline sending mode</a>.</li><li>The KSeF system accepts exclusively the value contained in the <code>P_1</code> field of the e-invoice structure as the issue date.</li><li>The invoice receipt date is the date of KSeF number assignment or, in case of sharing outside KSeF, the date of actual receipt.</li><li>After issuing an invoice in offline mode, the client application should generate two <a href="./kody-qr.html">QR codes</a> for invoice visualization: <ul><li><strong>CODE I</strong> – enables invoice verification in the KSeF system,</li><li><strong>CODE II</strong> – confirms issuer identity.</li></ul></li><li>A corrective invoice is sent only after the original document has been assigned a KSeF number.</li><li>If a sent offline invoice is rejected for technical reasons, it is possible to use the <a href="/ksef-docs/offline/korekta-techniczna.html">technical correction</a> mechanism.</li></ul><h3 id="overview-of-invoice-issuing-modes-in-ksef-–-offline24-offline-and-emergency" tabindex="-1">Overview of invoice issuing modes in KSeF – offline24, offline and emergency <a class="header-anchor" href="#overview-of-invoice-issuing-modes-in-ksef-–-offline24-offline-and-emergency" aria-label="Permalink to &quot;Overview of invoice issuing modes in KSeF – offline24, offline and emergency&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Responsibility side</th><th>Launch circumstances</th><th>Deadline for sending to KSeF</th><th>Legal basis</th></tr></thead><tbody><tr><td><strong>offline24</strong></td><td>client</td><td>No restrictions (taxpayer&#39;s discretion)</td><td>by the next business day after the issue date</td><td>art. 106nda VAT Act (KSeF 2.0 project)</td></tr><tr><td><strong>offline</strong></td><td>KSeF system</td><td>System unavailability (announced in BIP and interface software)</td><td>by the next business day after the end of unavailability</td><td>art. 106nh VAT Act (from 1 II 2026)</td></tr><tr><td><strong>emergency</strong></td><td>KSeF system</td><td>KSeF failure (message in MF BIP and interface software)</td><td>up to 7 business days from the end of failure (with the next message the counter starts over)</td><td>art. 106nf VAT Act (from 1 II 2026)</td></tr></tbody></table><h3 id="deadline-for-sending-invoice-to-ksef-for-subsequent-events" tabindex="-1">Deadline for sending invoice to KSeF for subsequent events <a class="header-anchor" href="#deadline-for-sending-invoice-to-ksef-for-subsequent-events" aria-label="Permalink to &quot;Deadline for sending invoice to KSeF for subsequent events&quot;">​</a></h3><p>In offline24 and offline modes, if a KSeF failure is announced during the expected period for sending invoices (message in MF BIP or interface software), the sending deadline is moved and counted from the day the last announced failure ends, no longer than 7 business days.</p><p>In emergency mode, if another failure message appears during the seven-day period for sending invoices, the deadline counter resets and runs from the day this subsequent failure ends.</p><p>Announcement of a total failure during any of the above modes results in the removal of the obligation to send invoices to KSeF.</p><h4 id="example-offline24-mode-with-announced-ksef-failure" tabindex="-1">Example: offline24 mode with announced KSeF failure <a class="header-anchor" href="#example-offline24-mode-with-announced-ksef-failure" aria-label="Permalink to &quot;Example: offline24 mode with announced KSeF failure&quot;">​</a></h4><ol><li>2025-07-08 (Wednesday) <ul><li>Taxpayer generates invoice in offline24 mode (offlineMode = true).</li><li>Deadline for sending to KSeF is set to 2025-07-09 (next business day).</li></ul></li><li>2025-07-09 (Thursday) <ul><li>Ministry of Finance publishes communication about KSeF failure (BIP and API interface).</li><li>According to the rule: the original deadline is moved, and the new one is counted from the day the failure ends.</li></ul></li><li>2025-07-12 (Saturday) <ul><li>Failure is removed – system available again.</li><li>A period of 7 business days begins for sending the overdue invoice.</li></ul></li><li>2025-07-22 (Tuesday) <ul><li>The 7 business day deadline from the end of failure expires.</li><li>The application has until this date to send the invoice to KSeF with offlineMode = true set.</li></ul></li></ol><h3 id="total-failure-mode" tabindex="-1">Total failure mode <a class="header-anchor" href="#total-failure-mode" aria-label="Permalink to &quot;Total failure mode&quot;">​</a></h3><p>In case of announcement of total failure (social media: TV, radio, press, Internet):</p><ul><li>Invoice can be issued in paper or electronic form, without the obligation to use the FA(3) template.</li><li>There is no obligation to send the invoice to KSeF after the failure ends.</li><li>Transfer to the buyer takes place through any channel (in person, email, other).</li><li>The issue date is always the actual date indicated on the invoice and the receipt date is the date of actual receipt of the purchase invoice.</li><li>Invoices from this mode are not marked with QR codes.</li><li>A corrective invoice during an ongoing KSeF failure is issued analogously – outside KSeF, with the actual date.</li></ul><h2 id="related-documents" tabindex="-1">Related documents <a class="header-anchor" href="#related-documents" aria-label="Permalink to &quot;Related documents&quot;">​</a></h2><ul><li><a href="./offline/korekta-techniczna.html">Technical correction of offline invoice</a></li><li><a href="./kody-qr.html">QR codes</a></li></ul>',21)])])}const m=i(a,[["render",s]]);export{h as __pageData,m as default};
